import { Link } from "react-router-dom";
import { ArrowLeft } from "lucide-react";

/**
 * Dashboard Pro gateway card - horizontal professional layout
 * Props: { to, label, description, icon: Icon, count, countSuffix, accent: "blue|amber|emerald|rose|violet|sky" }
 */
const ACCENT_STYLES = {
  blue:    { bg: "bg-[#0f3a73]", light: "bg-blue-50", text: "text-[#0f3a73]", border: "border-[#0f3a73]/20", hover: "hover:bg-[#0f3a73]/5" },
  amber:   { bg: "bg-amber-500", light: "bg-amber-50", text: "text-amber-700", border: "border-amber-500/20", hover: "hover:bg-amber-50" },
  emerald: { bg: "bg-emerald-500", light: "bg-emerald-50", text: "text-emerald-700", border: "border-emerald-500/20", hover: "hover:bg-emerald-50" },
  rose:    { bg: "bg-rose-500", light: "bg-rose-50", text: "text-rose-700", border: "border-rose-500/20", hover: "hover:bg-rose-50" },
  violet:  { bg: "bg-violet-500", light: "bg-violet-50", text: "text-violet-700", border: "border-violet-500/20", hover: "hover:bg-violet-50" },
  sky:     { bg: "bg-sky-500", light: "bg-sky-50", text: "text-sky-700", border: "border-sky-500/20", hover: "hover:bg-sky-50" },
};

export default function GatewayCard({ to, label, description, icon: Icon, count = 0, countSuffix = "سجل", accent = "blue", testIdKey }) {
  const styles = ACCENT_STYLES[accent] || ACCENT_STYLES.blue;

  return (
    <Link
      to={to}
      className={`group relative block overflow-hidden rounded-xl border-2 ${styles.border} bg-white transition-all duration-300 ${styles.hover} hover:shadow-lg`}
      data-testid={`gateway-card-${testIdKey}`}
    >
      {/* Header: Icon + Title + Badge */}
      <div className="flex items-center justify-between gap-4 p-5 pb-4">
        <div className="flex items-center gap-4">
          <div className={`grid h-12 w-12 flex-shrink-0 place-items-center rounded-lg ${styles.bg}`} data-testid={`gateway-card-icon-${testIdKey}`}>
            {Icon ? <Icon className="h-6 w-6 text-white" /> : null}
          </div>
          <div>
            <h3 className="text-lg font-extrabold text-slate-900" data-testid={`gateway-card-title-${testIdKey}`}>
              {label}
            </h3>
            {description && (
              <p className="mt-0.5 text-xs text-slate-500" data-testid={`gateway-card-desc-${testIdKey}`}>
                {description}
              </p>
            )}
          </div>
        </div>
        <div className={`flex-shrink-0 rounded-full ${styles.light} px-4 py-2`} data-testid={`gateway-card-count-${testIdKey}`}>
          <div className={`text-center text-lg font-extrabold ${styles.text}`}>
            {count.toLocaleString('ar-EG')}
          </div>
          <div className={`text-[10px] font-bold ${styles.text}`}>
            {countSuffix}
          </div>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="px-5 pb-4">
        <div className="h-1.5 w-full overflow-hidden rounded-full bg-slate-100">
          <div 
            className={`h-full ${styles.bg} transition-all duration-700 ease-out`}
            style={{ width: count > 0 ? '75%' : '0%' }}
          />
        </div>
      </div>

      {/* Footer: CTA Button */}
      <div className={`border-t ${styles.border} px-5 py-3`}>
        <div className={`inline-flex items-center gap-2 text-sm font-bold ${styles.text} transition-transform duration-200 group-hover:-translate-x-1`} data-testid={`gateway-card-open-${testIdKey}`}>
          <span>عرض السجلات</span>
          <ArrowLeft className="h-4 w-4" />
        </div>
      </div>
    </Link>
  );
}
